completions.insertText:
http {
    include       mime.types;
    default_type  application/octet-stream;
    sendfile      on;
    keepalive_timeout  65;

    ${1:# server blocks}
}

events {
    worker_connections  ${1:1024};
    multi_accept on;
    use epoll;
}

server {
    listen 443 ssl http2;
    listen [::]:443 ssl http2;
    server_name ${1:example.com};

    ssl_certificate     /etc/letsencrypt/live/${1:example.com}/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/${1:example.com}/privkey.pem;
    ssl_protocols       TLSv1.2 TLSv1.3;
    ssl_ciphers         HIGH:!aNULL:!MD5;
    ssl_prefer_server_ciphers on;
    ssl_session_cache   shared:SSL:10m;
    ssl_session_timeout 1d;

    add_header Strict-Transport-Security "max-age=63072000" always;
    add_header X-Frame-Options DENY;
    add_header X-Content-Type-Options nosniff;

    root /var/www/${1:example.com}/html;
    index index.html;

    location / {
        try_files \$uri \$uri/ =404;
    }
}

server {
    listen 80;
    listen [::]:80;
    server_name ${1:example.com} www.${1:example.com};
    return 301 https://\$host\$request_uri;
}

proxy_pass          http://${1:backend};
proxy_http_version  1.1;
proxy_set_header    Host              \$host;
proxy_set_header    X-Real-IP         \$remote_addr;
proxy_set_header    X-Forwarded-For   \$proxy_add_x_forwarded_for;
proxy_set_header    X-Forwarded-Proto \$scheme;
proxy_connect_timeout  ${2:60}s;
proxy_send_timeout     ${3:60}s;
proxy_read_timeout     ${4:60}s;
proxy_buffering        on;
proxy_buffer_size      128k;
proxy_buffers          4 256k;

proxy_cache_path /var/cache/nginx levels=1:2 keys_zone=${1:my_cache}:10m max_size=1g inactive=60m;

location / {
    proxy_cache ${1:my_cache};
    proxy_cache_valid 200 302 10m;
    proxy_cache_valid 404 1m;
    add_header X-Cache-Status \$upstream_cache_status;
    proxy_pass http://${2:backend};
}

location ${1:/ws} {
    proxy_pass http://${2:backend};
    proxy_http_version 1.1;
    proxy_set_header Upgrade \$http_upgrade;
    proxy_set_header Connection "upgrade";
    proxy_set_header Host \$host;
    proxy_read_timeout 86400s;
    proxy_send_timeout 86400s;
}

ssl_certificate     ${1:/etc/letsencrypt/live/example.com/fullchain.pem};
ssl_certificate_key ${2:/etc/letsencrypt/live/example.com/privkey.pem};
ssl_trusted_certificate ${3:/etc/letsencrypt/live/example.com/chain.pem};

ssl_protocols TLSv1.2 TLSv1.3;
ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
ssl_prefer_server_ciphers off;

ssl_session_cache shared:SSL:10m;
ssl_session_timeout 1d;
ssl_session_tickets off;

ssl_stapling on;
ssl_stapling_verify on;
resolver 8.8.8.8 8.8.4.4 valid=300s;
resolver_timeout 5s;

gzip on;
gzip_vary on;
gzip_proxied any;
gzip_comp_level ${1:6};
gzip_min_length 256;
gzip_types
    text/plain
    text/css
    text/javascript
    application/javascript
    application/json
    application/xml
    application/xml+rss
    image/svg+xml
    font/woff2;

# In http block:
limit_req_zone \$binary_remote_addr zone=${1:api_limit}:10m rate=${2:10}r/s;

# In location block:
limit_req zone=${1:api_limit} burst=${3:20} nodelay;
limit_req_status 429;

# In http block:
limit_conn_zone \$binary_remote_addr zone=${1:conn_limit}:10m;

# In server/location:
limit_conn ${1:conn_limit} ${2:10};

add_header X-Frame-Options "SAMEORIGIN" always;
add_header X-Content-Type-Options "nosniff" always;
add_header X-XSS-Protection "1; mode=block" always;
add_header Referrer-Policy "strict-origin-when-cross-origin" always;
add_header Content-Security-Policy "default-src 'self'; script-src 'self' 'unsafe-inline'; style-src 'self' 'unsafe-inline'" always;
add_header Permissions-Policy "camera=(), microphone=(), geolocation=()" always;
add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;

add_header Access-Control-Allow-Origin "${1:*}";
add_header Access-Control-Allow-Methods "GET, POST, PUT, DELETE, OPTIONS";
add_header Access-Control-Allow-Headers "Authorization, Content-Type, Accept";
add_header Access-Control-Max-Age 86400;

if (\$request_method = OPTIONS) {
    return 204;
}

location ~ \.php$ {
    include fastcgi_params;
    fastcgi_pass unix:/run/php/php${1:8.2}-fpm.sock;
    fastcgi_param SCRIPT_FILENAME \$document_root\$fastcgi_script_name;
    fastcgi_index index.php;
    fastcgi_intercept_errors on;
    fastcgi_buffer_size 16k;
    fastcgi_buffers 4 16k;
}

sendfile on;
tcp_nopush on;
tcp_nodelay on;

location ~* \.(css|js|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot)$ {
    expires 1y;
    add_header Cache-Control "public, immutable";
    access_log off;
    log_not_found off;
}

server {
    listen 80;
    server_name ${1:api.example.com};

    location / {
        proxy_pass http://127.0.0.1:${2:3000};
        proxy_http_version 1.1;
        proxy_set_header Upgrade \$http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host \$host;
        proxy_set_header X-Real-IP \$remote_addr;
        proxy_set_header X-Forwarded-For \$proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto \$scheme;
        proxy_cache_bypass \$http_upgrade;
    }
}

server {
    listen 80;
    server_name ${1:example.com};
    root /var/www/${1:example.com}/public;

    add_header X-Frame-Options "SAMEORIGIN";
    add_header X-Content-Type-Options "nosniff";

    index index.php;
    charset utf-8;

    location / {
        try_files \$uri \$uri/ /index.php?\$query_string;
    }

    location = /favicon.ico { access_log off; log_not_found off; }
    location = /robots.txt  { access_log off; log_not_found off; }

    error_page 404 /index.php;

    location ~ \.php$ {
        fastcgi_pass unix:/run/php/php${2:8.2}-fpm.sock;
        fastcgi_param SCRIPT_FILENAME \$realpath_root\$fastcgi_script_name;
        include fastcgi_params;
    }

    location ~ /\.(?!well-known).* {
        deny all;
    }
}

server {
    listen 80;
    server_name ${1:example.com};
    root /var/www/wordpress;

    index index.php;

    location / {
        try_files \$uri \$uri/ /index.php?\$args;
    }

    location ~ \.php$ {
        include fastcgi_params;
        fastcgi_pass unix:/run/php/php${2:8.2}-fpm.sock;
        fastcgi_param SCRIPT_FILENAME \$document_root\$fastcgi_script_name;
    }

    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg)$ {
        expires 30d;
        log_not_found off;
    }

    location ~ /\. {
        deny all;
    }

    location = /xmlrpc.php {
        deny all;
    }
}

user ${1:www-data};
worker_processes auto;
pid /run/nginx.pid;
error_log /var/log/nginx/error.log warn;

events {
    worker_connections 1024;
    multi_accept on;
}

http {
    include       mime.types;
    default_type  application/octet-stream;

    log_format main '\$remote_addr - \$remote_user [\$time_local] "\$request" '
                    '\$status \$body_bytes_sent "\$http_referer" '
                    '"\$http_user_agent"';
    access_log /var/log/nginx/access.log main;

    sendfile        on;
    tcp_nopush      on;
    tcp_nodelay     on;
    keepalive_timeout 65;
    types_hash_max_size 2048;
    client_max_body_size 50m;

    gzip on;
    gzip_vary on;
    gzip_types text/plain text/css application/json application/javascript text/xml;

    include /etc/nginx/conf.d/*.conf;
    include /etc/nginx/sites-enabled/*;
}

