	}
	server {
		listen ${3:3306};
		proxy_pass ${1:backend};
	}
}

documentation.value:
Implements authentication via subrequest.

```nginx
location /protected/ {
    auth_request /auth;
    auth_request_set $auth_user $upstream_http_x_user;
}

location = /auth {
    internal;
    proxy_pass http://auth-server/verify;
    proxy_pass_request_body off;
    proxy_set_header Content-Length "";
}
```

Define header to extract real client IP (behind proxy/CDN).

```nginx
real_ip_header X-Forwarded-For;
# or: real_ip_header X-Real-IP;
# or: real_ip_header proxy_protocol;
```

Specify trusted proxy addresses for real IP extraction.

```nginx
set_real_ip_from 10.0.0.0/8;
set_real_ip_from 172.16.0.0/12;
set_real_ip_from 192.168.0.0/16;
real_ip_header X-Forwarded-For;
real_ip_recursive on;
```

Specify when to pass request to next upstream server.

```nginx
proxy_next_upstream error timeout http_502 http_503;
proxy_next_upstream_tries 3;
proxy_next_upstream_timeout 10s;
```

Pass request to a uWSGI application server.

```nginx
location / {
    uwsgi_pass unix:///tmp/uwsgi.sock;
    include uwsgi_params;
}
```

Pass request to a gRPC backend.

```nginx
location / {
    grpc_pass grpc://127.0.0.1:50051;
}
```

Mark a location as internal (only accessible via internal redirect, error_page, auth_request).

```nginx
location /internal {
    internal;
    proxy_pass http://backend;
}
```

Enable stub_status for monitoring.

```nginx
location /nginx_status {
    stub_status;
    allow 127.0.0.1;
    deny all;
}
```

Enable verification of OCSP responses.

```nginx
ssl_stapling on;
ssl_stapling_verify on;
ssl_trusted_certificate /etc/ssl/certs/ca-certificates.crt;
```

Reverse proxy for Django/Python apps behind Gunicorn or uWSGI.

```nginx
server {
    listen 80;
    server_name example.com;
    location / {
        proxy_pass http://127.0.0.1:8000;
        proxy_set_header Host $host;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
    location /static/ {
        alias /var/www/static/;
    }
}
```

